module top_module (
    input c,
    input m,
    input e,
    input d,
    output reg valid_q
);
    always @(*) begin
        case ({c, m, e, d})
            4'b0010: valid_q = 1'b0;
            4'b0100: valid_q = 1'b0;
            4'b0101: valid_q = 1'b0;
            4'b1001: valid_q = 1'b0;
            4'b0001: valid_q = 1'b1;
            4'b1011: valid_q = 1'b0;
            4'b1010: valid_q = 1'b0;
            4'b0000: valid_q = 1'b1;
            4'b0011: valid_q = 1'b0;
            4'b1101: valid_q = 1'b1;
            4'b1000: valid_q = 1'b0;
            4'b1100: valid_q = 1'b1;
            4'b0111: valid_q = 1'b1;
            4'b1110: valid_q = 1'b0;
            4'b1111: valid_q = 1'b1;
            4'b0110: valid_q = 1'b0;
        endcase
    end
endmodule
